mapper.select:
select * from IRRIGATION_QUOTA_DETAILS


        and STATION = #{req.station}


        and WATER_USER = #{req.unit}


        and CROP_TYPE = #{req.cropType}


        and TO_CHAR(CREATE_TIME,'YYYY-MM') between #{req.startTime} and #{req.endTime}

SELECT * FROM( SELECT YEAR(T2.CREATE_TIME) AS YEAR, MONTH(T2.CREATE_TIME) AS MONTH, CASE WHEN T2.TEN_DAYS = '上旬' THEN 1 WHEN T2.TEN_DAYS = '中旬' THEN 2 ELSE 3 END AS INDEX1 , T2.TEN_DAYS, T2.STATION, T2.WATER_USER, T2.CROP_TYPE, T2.IRRIGATION_CROP, ROUND( CASE WHEN T2.IRRIGATION_WATER_VOLUME IS NULL THEN 0.0 ELSE T2.IRRIGATION_WATER_VOLUME END,3) AS SJ_VOLUME, ROUND( CASE WHEN T1.WATER_DEMAND IS NULL THEN 0.0 ELSE T1.WATER_DEMAND END,3) AS JH_VOLUME, ROUND( CASE WHEN T2.IRRIGATION_AREA IS NULL THEN 0.0 ELSE T2.IRRIGATION_AREA END,3) AS SJ_AREA, ROUND( CASE WHEN T1.IRRIGATED_AREA IS NULL THEN 0.0 ELSE T1.IRRIGATED_AREA END,3) AS JH_AREA FROM "TTH"."IRRIGATION_QUOTA_DETAILS" T2 LEFT JOIN "TTH"."TEN_DAY_WATER_USE_PLAN" T1 ON T1.YEAR = YEAR(T2.CREATE_TIME) AND T1.MONTH = MONTH(T2.CREATE_TIME) AND T1.TEN_DAYS = T2.TEN_DAYS AND T1.AREA = T2.STATION AND T1.USE_WATER_USER = T2.WATER_USER AND T1.CROP_TYPE = T2.CROP_TYPE AND T1.IRRIGATED_CROP = T2.IRRIGATION_CROP WHERE 1 = 1
AND T2.STATION = #{req.station}
AND T2.WATER_USER = #{req.unit}
AND T2.CROP_TYPE = #{req.cropType}
)T1
WHERE (YEAR = YEAR(#{req.startTime}) AND MONTH >= MONTH(#{req.startTime})) OR (YEAR = YEAR(#{req.endTime}) AND MONTH <= MONTH(#{req.endTime}))
ORDER BY YEAR, MONTH, INDEX1, STATION, WATER_USER, CROP_TYPE, IRRIGATION_CROP
